Today, I'm able to append or set pipeline stages on the aggregation cursor as follows...

 
{code:java}
const cur = db.collection('my-collection').aggregate()
cur.match({ .... }){code}
However, $search isn't support. 

 

I propose the following change. Note: I would have submitted a PR but it's not clear to me how I gain access to push "ERROR: Permission to mongodb/node-mongodb-native.git denied to ws-gregm."
{code:java}
diff --git a/src/cursor/aggregation_cursor.ts b/src/cursor/aggregation_cursor.ts
index c2979199e..12b0b4122 100644
--- a/src/cursor/aggregation_cursor.ts
+++ b/src/cursor/aggregation_cursor.ts
@@ -101,6 +101,13 @@ export class AggregationCursor<TSchema = any> extends AbstractCursor<TSchema> {
     return this;
   }
 
+  /** Add a search stage to the aggregation pipeline */
+  match($search: Document): this {
+    assertUninitialized(this);
+    this[kPipeline].push({ $search });
+    return this;
+  } {code}

